import { GoogleGenAI, Type } from "@google/genai";
import { RouteOption, TravelMode, UserProfile } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateRoutes = async (
  origin: string,
  destination: string,
  mode: TravelMode,
  profile: UserProfile
): Promise<RouteOption[]> => {
  const prompt = `
    Generate 3 distinct ${mode} route options from "${origin}" to "${destination}".
    User Profile:
    - She Nav Enabled: ${profile.sheNavEnabled}
    - Mobility Needs: ${profile.mobilityNeeds}
    - Safety Priority: ${profile.safetyPriority}%

    Each route should have:
    - name: A descriptive name
    - distance: approximate distance in km/meters
    - duration: approximate duration in minutes
    - comfortScore: 0-100 score based on lighting, crowd, and reported safety.
    - comfortBreakdown: sub-scores for safety, lighting, crowd, and accessibility (0-100 each).
    - type: One of 'Safest', 'Balanced', 'Fastest'.
    - tags: Short descriptors like "Well lit", "Few turns", "Busy street".
    - landmarks: 2-3 prominent landmarks along the way.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              id: { type: Type.STRING },
              name: { type: Type.STRING },
              distance: { type: Type.STRING },
              duration: { type: Type.STRING },
              comfortScore: { type: Type.NUMBER },
              comfortBreakdown: {
                type: Type.OBJECT,
                properties: {
                  safety: { type: Type.NUMBER },
                  lighting: { type: Type.NUMBER },
                  crowd: { type: Type.NUMBER },
                  accessibility: { type: Type.NUMBER },
                },
              },
              tags: { type: Type.ARRAY, items: { type: Type.STRING } },
              landmarks: { type: Type.ARRAY, items: { type: Type.STRING } },
              type: { type: Type.STRING },
            },
          },
        },
      },
    });

    const routes = JSON.parse(response.text || "[]");
    return routes.map((r: any) => ({
      ...r,
      id: Math.random().toString(36).substr(2, 9),
    }));
  } catch (error) {
    console.error("Error generating routes:", error);
    // Fallback mock data
    return [
      {
        id: "mock-1",
        name: "Main St Safety Corridor",
        distance: "1.2 km",
        duration: "15 min",
        comfortScore: 92,
        comfortBreakdown: { safety: 95, lighting: 90, crowd: 85, accessibility: 95 },
        tags: ["Well lit", "CCTV active", "Step-free"],
        landmarks: ["Central Park South", "City Library"],
        type: "Safest",
      },
    ];
  }
};

export const getSafetyInsights = async (area: string): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Provide 3 short, actionable safety tips for a traveler in the area: ${area}. Focus on lighting, crowd density, and accessibility.`,
    });
    return response.text || "Stay alert and prefer well-lit main streets.";
  } catch (error) {
    return "Local insights are currently unavailable. Stay on main paths.";
  }
};

