import { GoogleGenAI, Type } from "@google/genai";
import { RouteOption, TravelMode, UserProfile } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateRoutes = async (
  origin: string,
  destination: string,
  mode: TravelMode,
  profile: UserProfile
): Promise<RouteOption[]> => {
  const isMetro = mode === 'metro';
  const modeSpecificContext = isMetro 
    ? "For Metro routes, focus on station safety, platform lighting, presence of transit police/staff, and elevator/escalator status for accessibility."
    : `Focus on ${mode} safety, including street lighting and crowd density.`;

  const prompt = `
    Generate 3 distinct ${mode} route options from "${origin}" to "${destination}".
    User Profile:
    - She Nav Enabled: ${profile.sheNavEnabled}
    - Mobility Needs: ${profile.mobilityNeeds}
    - Safety Priority: ${profile.safetyPriority}%

    ${modeSpecificContext}

    Each route should have:
    - name: A descriptive name (e.g., 'Blue Line via Central')
    - distance: approximate distance in km/meters
    - duration: approximate duration in minutes
    - comfortScore: 0-100 score based on ${isMetro ? 'station lighting, staff presence, and security' : 'lighting, crowd, and reported safety'}.
    - comfortBreakdown: sub-scores for safety, lighting, crowd, and accessibility (0-100 each).
    - type: One of 'Safest', 'Balanced', 'Fastest'.
    - tags: Short descriptors (e.g., "Staffed Station", "Bright Platform", "Step-free").
    - landmarks: 2-3 prominent landmarks or station stops along the way.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              id: { type: Type.STRING },
              name: { type: Type.STRING },
              distance: { type: Type.STRING },
              duration: { type: Type.STRING },
              comfortScore: { type: Type.NUMBER },
              comfortBreakdown: {
                type: Type.OBJECT,
                properties: {
                  safety: { type: Type.NUMBER },
                  lighting: { type: Type.NUMBER },
                  crowd: { type: Type.NUMBER },
                  accessibility: { type: Type.NUMBER },
                },
              },
              tags: { type: Type.ARRAY, items: { type: Type.STRING } },
              landmarks: { type: Type.ARRAY, items: { type: Type.STRING } },
              type: { type: Type.STRING },
            },
          },
        },
      },
    });

    const routes = JSON.parse(response.text || "[]");
    return routes.map((r: any) => ({
      ...r,
      id: Math.random().toString(36).substr(2, 9),
    }));
  } catch (error) {
    console.error("Error generating routes:", error);
    return [
      {
        id: "mock-metro-1",
        name: isMetro ? "Express Line via North Station" : "Main St Safety Corridor",
        distance: "2.4 km",
        duration: "12 min",
        comfortScore: 88,
        comfortBreakdown: { safety: 90, lighting: 92, crowd: 70, accessibility: 95 },
        tags: isMetro ? ["Staffed Station", "Well Lit", "Elevator Access"] : ["Well lit", "CCTV active"],
        landmarks: isMetro ? ["North Station Plaza", "Transit HQ"] : ["Central Park South"],
        type: "Safest",
      },
    ];
  }
};

