  name: string;
  distance: string;
  duration: string;
  comfortScore: number;
  comfortBreakdown: {
    safety: number;
    lighting: number;
    crowd: number;
    accessibility: number;
  };
  tags: string[];
  landmarks: string[];
  type: 'Safest' | 'Balanced' | 'Fastest';
}

