      <div className="relative z-10 w-full max-w-sm flex flex-col items-center text-center">
        <div className="w-24 h-24 bg-white/20 rounded-full flex items-center justify-center animate-ping mb-8">
          <Icons.Alert />
        </div>

        <h2 className="text-4xl font-black mb-2 uppercase tracking-tighter">SOS Active</h2>
        <p className="text-red-100 font-bold mb-8">{panicStatus}</p>

        <div className="w-full bg-red-700/50 rounded-2xl p-4 text-left space-y-2 mb-8 font-mono text-xs">
          {panicLog.map((log, i) => (
            <div key={i} className="flex items-center gap-2">
              <span className="text-red-300">>></span> {log}
            </div>
          ))}
        </div>

        <button 
          onClick={() => setIsPanicMode(false)}
          className="w-full bg-white text-red-600 py-4 rounded-2xl font-black shadow-xl active:scale-95 transition-all"
        >
          CANCEL SOS
        </button>
      </div>
    </div>
  );

